def verify_webhook_signature(payload: bytes, secret: str, signature: str) -> bool:
    """Verify the webhook signature using HMAC-SHA256."""
    expected_signature = hmac.new(
        secret.encode("utf-8"),
        payload,
        hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest(expected_signature, signature)


def parse_payment_notification(body: dict) -> dict:
    """Parse and validate the payment notification payload."""
    # Support multiple provider formats
    payment_data = {}

    # Detect provider format and normalize
    if "event_type" in body:
        # Standard format
        payment_data = {
            "event_type": body["event_type"],
            "transaction_id": body.get("transaction_id") or body.get("id"),
            "amount": body.get("amount"),
            "currency": body.get("currency", "USD"),
            "status": body.get("status"),
            "provider": body.get("provider", "unknown"),
            "customer_id": body.get("customer_id"),
            "metadata": body.get("metadata", {}),
            "timestamp": body.get("timestamp", datetime.utcnow().isoformat()),
            "raw_payload": body
        }
    elif "type" in body and "data" in body:
        # Stripe-like format
        event_data = body.get("data", {}).get("object", {})
        payment_data = {
            "event_type": body["type"],
            "transaction_id": event_data.get("id") or body.get("id"),
            "amount": event_data.get("amount"),
            "currency": event_data.get("currency", "usd"),
            "status": event_data.get("status"),
            "provider": "stripe",
            "customer_id": event_data.get("customer"),
            "metadata": event_data.get("metadata", {}),
            "timestamp": body.get("created", datetime.utcnow().isoformat()),
            "raw_payload": body
        }
    elif "event" in body and "payload" in body:
        # PayPal-like format
        payload = body.get("payload", {})
        payment_data = {
            "event_type": body["event"],
            "transaction_id": payload.get("id") or body.get("id"),
            "amount": payload.get("amount", {}).get("value"),
            "currency": payload.get("amount", {}).get("currency_code", "USD"),
            "status": payload.get("status"),
            "provider": "paypal",
            "customer_id": payload.get("payer", {}).get("payer_id"),
            "metadata": payload.get("custom_data", {}),
            "timestamp": body.get("create_time", datetime.utcnow().isoformat()),
            "raw_payload": body
        }
    else:
        # Generic fallback
        payment_data = {
            "event_type": body.get("event_type", body.get("type", body.get("event", "unknown"))),
            "transaction_id": body.get("transaction_id", body.get("id", "unknown")),
            "amount": body.get("amount"),
            "currency": body.get("currency", "USD"),
            "status": body.get("status", "unknown"),
            "provider": body.get("provider", "unknown"),
            "customer_id": body.get("customer_id"),
            "metadata": {},
            "timestamp": datetime.utcnow().isoformat(),
            "raw_payload": body
        }

    # Validate required fields
    if not payment_data.get("transaction_id"):
        raise KeyError("transaction_id")
    if not payment_data.get("event_type"):
        raise KeyError("event_type")

    return payment_data


